SELECT event_name
FROM sailing_events
WHERE status = 'Planned';

SELECT COUNT(boat_id) AS boat_count
FROM event_boats
WHERE event_id = 1;

SELECT COUNT(race_id) AS race_count
FROM races
WHERE event_id = (SELECT event_id FROM sailing_events WHERE event_name = 'Sailing Regatta');

SELECT COUNT(sailor_id) AS total_sailors
FROM event_sailors
WHERE event_id = 1;
